```powershell
# Fonctions de validation réutilisables
function Test-Email {
    param([string]$Email)
    return $Email -match '^[\w.+-]+@[\w-]+\.[\w.]+$'
}

function Test-CodePostal {
    param([string]$Code)
    return $Code -match '^\d{5}$'
}

function Test-IPv4 {
    param([string]$IP)
    if ($IP -notmatch '^(\d{1,3}\.){3}\d{1,3}$') { return $false }
    return ($IP -split '\.') | ForEach-Object { [int]$_ } |
        Where-Object { $_ -gt 255 } | Measure-Object | 
        Select-Object -ExpandProperty Count | ForEach-Object { $_ -eq 0 }
}

# Utilisation
@("alice@example.com", "pas_email", "test@") | ForEach-Object {
    $valid = Test-Email $_
    [PSCustomObject]@{ Email = $_; Valide = $valid }
} | Format-Table
```

